import { useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';

/**
 * Page callback Google OAuth2.
 * Route : /google-callback (HORS du Layout, HORS de la protection Keycloak)
 *
 * Google redirige ici avec ?code=...&state=...
 * On envoie le code au backend, puis on redirige vers /agenda.
 */
export default function GoogleCallback() {
  const navigate = useNavigate();
  const handled = useRef(false); // évite le double appel en StrictMode

  useEffect(() => {
    if (handled.current) return;
    handled.current = true;

    const params = new URLSearchParams(window.location.search);
    const code = params.get('code');
    const error = params.get('error');

    if (error || !code) {
      // Accès refusé ou annulé par l'utilisateur
      navigate('/agenda?google=denied', { replace: true });
      return;
    }

    api.post('/calendar/oauth/callback', { code })
      .then(() => {
        navigate('/agenda?google=success', { replace: true });
      })
      .catch(() => {
        navigate('/agenda?google=error', { replace: true });
      });
  }, [navigate]);

  return (
    <div style={{
      display: 'flex', flexDirection: 'column',
      alignItems: 'center', justifyContent: 'center',
      height: '100vh', gap: 16,
      fontFamily: 'sans-serif', color: '#555',
    }}>
      {/* Spinner simple */}
      <svg
        width="32" height="32" viewBox="0 0 24 24"
        fill="none" stroke="#1a73e8" strokeWidth="2"
        strokeLinecap="round" strokeLinejoin="round"
        style={{ animation: 'spin 1s linear infinite' }}
      >
        <path d="M21 12a9 9 0 11-6.219-8.56"/>
      </svg>
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
      <span style={{ fontSize: 15 }}>Connexion à Google Calendar...</span>
    </div>
  );
}
